(function(){function initASVideoBG(root=document){const nodes=root.querySelectorAll("[data-as-video-bg]");nodes.forEach(function(el){const url=el.dataset.asVideoBg;const poster=el.dataset.asVideoPoster;const parallax=JSON.parse(el.dataset.parallax||"{}");let position=el.dataset.asVideoPosition;if(typeof position==="undefined"||position===""){position="absolute"}el.classList.add("position-relative");Array.from(el.children).forEach(function(child){child.classList.add("position-relative","z-1")});const container=document.createElement("div");container.classList.add("astroid-element-overlay","position-"+position,"top-0","start-0","w-100","h-100","overflow-hidden","z-0","pe-none");if(typeof poster!=="undefined"&&poster){container.style.background="url("+poster+")";container.style.backgroundSize="cover";container.style.backgroundPosition="center center"}const video=document.createElement("video");video.setAttribute("playsinline","");video.playsInline=true;video.loop=true;video.src=url;video.classList.add("position-absolute","top-50","start-50","object-fit-cover");video.style.minWidth="100%";video.style.minHeight="120%";video.style.transform="translate(-50%, -50%)";video.style.zIndex="-100";container.appendChild(video);if(el.firstChild){el.insertBefore(container,el.firstChild)}else{el.appendChild(container)}video.muted=true;const playPromise=video.play();if(playPromise&&typeof playPromise.catch==="function"){playPromise.catch(function(){})}if(el.dataset.parallax&&parallax.type==="video"&&typeof gsap!=="undefined"){const speed=Number(parallax.speed)||.3;const startPercent=-20-50;const endPercent=20*speed-50;const startTrigger=parallax.start||"top bottom";const endTrigger=parallax.end||"bottom top";let scrub=true;if(typeof parallax.scrub!=="undefined"){if(parallax.scrub===false||parallax.scrub==="false")scrub=false;else if(parallax.scrub===true||parallax.scrub==="true")scrub=true;else scrub=Number(parallax.scrub)||true}if(typeof ScrollTrigger!=="undefined"){if(!initASVideoBG._scrollTriggerRegistered){gsap.registerPlugin(ScrollTrigger);initASVideoBG._scrollTriggerRegistered=true}gsap.set(video,{yPercent:startPercent,willChange:"transform"});gsap.to(video,{yPercent:endPercent,ease:"none",scrollTrigger:{trigger:el,start:startTrigger,end:endTrigger,scrub:scrub,invalidateOnRefresh:true}})}}})}if(document.readyState==="loading"){document.addEventListener("DOMContentLoaded",function(){initASVideoBG()})}else{initASVideoBG()}})();